1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const PROCESSING_FEE = 5;
11	const INITIAL_ASSESSMENT_MULTIPLIER = 1.1;
12	const ALIKE_BUNDLE_DISCOUNT = 15;
13	const CURSED_SURCHARGE_MULTIPLIER = 1.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER = 1.3;
15	const HIGH_ENCHANTMENT_THRESHOLD = 5;
16	const COMPONENT_TYPES = ["rune", "moonstone"];
17	
18	function ceilToWholeGold(amount: number): number {
19	  return Math.ceil(Math.round(amount * 1e6) / 1e6);
20	}
21	
22	function basePremiumFor(itemType: string): number {
23	  return BASE_PREMIUMS[itemType] ?? 0;
24	}
25	
26	function isHighlyEnchanted(item: { enchantment?: number }): boolean {
27	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
28	}
29	
30	function itemPremium(item: { type: string; cursed?: boolean; enchantment?: number }): number {
31	  const base = basePremiumFor(item.type);
32	  if (item.cursed) return base * CURSED_SURCHARGE_MULTIPLIER;
33	  if (isHighlyEnchanted(item)) return base * HIGH_ENCHANTMENT_SURCHARGE_MULTIPLIER;
34	  return base;
35	}
36	
37	function countOfType(items: Array<{ type: string }>, itemType: string): number {
38	  return items.filter((item) => item.type === itemType).length;
39	}
40	
41	function alikeBundleDiscount(items: Array<{ type: string }>): number {
42	  const bundleCount = COMPONENT_TYPES.reduce(
43	    (sum, componentType) => sum + Math.floor(countOfType(items, componentType) / 3),
44	    0,
45	  );
46	  return bundleCount * ALIKE_BUNDLE_DISCOUNT;
47	}
